css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #f4f5f7; color: #1a1a2e; }
.topbar { background: #1a1a2e; color: rgba(255,255,255,0.6); font-size: 12px; padding: 8px 60px; text-align: right; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 18px 60px; background: white; border-bottom: 2px solid #1a1a2e; }
.brand { font-size: 22px; font-weight: 900; letter-spacing: -0.02em; }
.brand span { color: #0891b2; }
.nav-links { display: flex; gap: 26px; }
.nav-links a { color: #555; text-decoration: none; font-size: 13.5px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.03em; }
.nav-links a.active { color: #0891b2; }
.subscribe { background: #1a1a2e; border: none; color: white; padding: 10px 22px; font-size: 12.5px; font-weight: 700; cursor: pointer; }
.breaking { background: #ef4444; color: white; padding: 12px 60px; display: flex; align-items: center; gap: 16px; font-size: 13.5px; font-weight: 600; }
.breaking-tag { background: white; color: #ef4444; font-weight: 900; font-size: 11px; padding: 4px 10px; letter-spacing: 0.05em; flex-shrink: 0; }
.featured { display: grid; grid-template-columns: 1.6fr 1fr; gap: 30px; padding: 36px 60px; }
.lead-img { height: 320px; background: linear-gradient(135deg, #0891b2, #155e75); border-radius: 10px; display: flex; align-items: center; justify-content: center; font-size: 70px; margin-bottom: 18px; }
.cat { display: inline-block; font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.05em; padding: 4px 10px; border-radius: 4px; margin-bottom: 10px; }
.cat-world { background: #dbeafe; color: #1d4ed8; }
.cat-tech { background: #ede9fe; color: #7c3aed; }
.cat-economy { background: #dcfce7; color: #16a34a; }
.cat-sport { background: #fee2e2; color: #dc2626; }
.cat-culture { background: #fef3c7; color: #d97706; }
.lead-story h1 { font-size: 32px; font-weight: 800; line-height: 1.3; margin-bottom: 12px; }
.lead-story p { color: #666; font-size: 15px; line-height: 1.7; margin-bottom: 14px; }
.meta { color: #999; font-size: 12.5px; font-weight: 600; }
.side-stories { display: flex; flex-direction: column; gap: 18px; }
.side-story { padding-bottom: 18px; border-bottom: 1px solid #e5e7eb; cursor: pointer; }
.side-story:last-child { border-bottom: none; }
.side-story h3 { font-size: 16px; font-weight: 700; line-height: 1.4; margin: 6px 0 8px; }
.grid-news { padding: 0 60px 50px; }
.grid-news h2 { font-size: 22px; font-weight: 800; margin-bottom: 20px; padding-top: 24px; border-top: 1px solid #e5e7eb; }
.news-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 22px; }
.news-card { background: white; border-radius: 10px; overflow: hidden; cursor: pointer; border: 1px solid #e5e7eb; transition: 0.15s; }
.news-card:hover { box-shadow: 0 12px 24px rgba(0,0,0,0.06); }
.thumb { height: 110px; background: #eef2f6; display: flex; align-items: center; justify-content: center; font-size: 36px; }
.news-card .cat { margin: 14px 14px 0; }
.news-card h3 { font-size: 14.5px; font-weight: 700; line-height: 1.4; margin: 10px 14px 8px; }
.news-card .meta { margin: 0 14px 14px; }
@media (max-width: 900px) { .navbar, .topbar, .breaking, .featured, .grid-news { padding-left: 24px; padding-right: 24px; } .featured { grid-template-columns: 1fr; } .nav-links { display: none; } }

